messages.content:
=Write a blog post with the following specifications:

Topic: {{ $('Webhook').item.json.body.topic }}
Target Keyword: {{ $('Webhook').item.json.body.target_keyword }}
Word Count: {{ $('Webhook').item.json.body.word_count }}
Tone: {{ $('Webhook').item.json.body.tone_override || $('Fetch Brand Voice').item.json.tone || 'professional' }}
Brand Voice: {{ $('Fetch Brand Voice').item.json.brand_voice }}
Niche: {{ $('Fetch Brand Voice').item.json.niche }}
Writing Style: {{ $('Fetch Brand Voice').item.json.writing_style }}

You MUST respond with ONLY a valid JSON object — no markdown, no code fences, no explanation. Use this exact schema:
{
  "title": "string",
  "meta_description": "string (max 160 chars)",
  "body_markdown": "string (full blog post in markdown)",
  "suggested_tags": ["string"],
  "readability_score": number (1-10)
}

parameters.jsCode:
const raw = $input.item.json;

// Extract text from Claude response
let contentText = '';
if (raw.content && Array.isArray(raw.content)) {
  contentText = raw.content
    .filter(block => block.type === 'text')
    .map(block => block.text)
    .join('');
} else {
  throw new Error('Unexpected Claude response shape: ' + JSON.stringify(raw));
}

// Strip markdown fences if Claude wrapped JSON anyway
const cleaned = contentText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse Claude JSON: ' + e.message + '\nRaw: ' + cleaned.substring(0, 300));
}

// Validate required keys
const required = ['title', 'meta_description', 'body_markdown', 'suggested_tags', 'readability_score'];
for (const key of required) {
  if (!(key in parsed)) {
    throw new Error(`Missing required key in Claude response: ${key}`);
  }
}

return {
  json: {
    ...parsed,
    user_id: $('Webhook').item.json.body.user_id,
    topic: $('Webhook').item.json.body.topic,
    target_keyword: $('Webhook').item.json.body.target_keyword
  }
};

